module top_module(din, rst, q, se, si, so);parameter SIZE = 1;

input	[SIZE-1:0]	din ;	
input			rst ;	

output	[SIZE-1:0]	q ;	

input			se ;	
input	[SIZE-1:0]	si ;	
output	[SIZE-1:0]	so ;	

reg 	[SIZE-1:0]	q ;

`ifdef NO_SCAN
always @ (posedge rst)
  q[SIZE-1:0]  <= din[SIZE-1:0] ;
`else

always @ (posedge rst)

	q[SIZE-1:0]  <= (se) ? si[SIZE-1:0]  : din[SIZE-1:0] ;

assign so[SIZE-1:0] = q[SIZE-1:0] ;

`endif

endmodule
